    "parameters": {
      "type": "object",
      "properties": {
        "tenant_id": {
          "type": "string",
          "description": "The unique identifier for the tenant (e.g., 'T-5001')."
        }
      },
      "required": [
        "tenant_id"
      ]
    },
    "example_output": {
      "tenant_id": "T-5001",
      "lease_id": "L-9902",
      "current_monthly_rent": 30000.0,
      "lease_expiry_date": "2024-12-31",
      "renewal_status": "not_started",
      "tenant_satisfaction_score": 8,
      "market_rent_average": 9.5
    }
  },
  "calculate_monthly_amortization": {
    "description": "Calculates the monthly payment amount for a capital expenditure based on principal, annual interest rate, and term length.",
    "parameters": {
      "type": "object",
      "properties": {
        "principal": {
          "type": "number",
          "description": "The total cost of the improvement (e.g., 240000)."
        },
        "annual_interest_rate": {
          "type": "number",
          "description": "The annual interest rate as a decimal (e.g., 0.08 for 8%)."
        },
        "term_years": {
          "type": "integer",
          "description": "The amortization period in years (e.g., 10)."
        }
      },
      "required": [
        "principal",
        "annual_interest_rate",
        "term_years"
      ]
    },
    "example_output": {
      "monthly_amortization_amount": 2911.58
    }
  },
  "submit_lease_renewal_proposal": {
    "description": "Sends a formal lease renewal proposal to the tenant with specific rent components and legal expense cap overrides.",
    "parameters": {
      "type": "object",
      "properties": {
        "tenant_id": {
          "type": "string",
          "description": "Unique identifier for the tenant."
        },
        "lease_id": {
          "type": "string",
          "description": "Unique identifier for the current lease."
        },
        "monthly_base_rent": {
          "type": "number",
          "description": "The base rent calculated from market rates."
        },
        "monthly_amortization_fee": {
          "type": "number",
          "description": "The additional monthly cost for capital recovery."
        },
        "bypass_controllable_cap": {
          "type": "boolean",
          "description": "If true, structures the amortization fee as a non-controllable expense to bypass the 5% cap."
        }
      },
      "required": [
        "tenant_id",
        "lease_id",
        "monthly_base_rent",
        "monthly_amortization_fee",
        "bypass_controllable_cap"
      ]
    },
    "example_output": {
      "proposal_status": "delivered",
      "updated_tenant_satisfaction_score": 7
    }
  },
  "update_renewal_status": {
    "description": "Updates the internal renewal phase of the lease in the system.",
    "parameters": {
      "type": "object",
      "properties": {
        "tenant_id": {
          "type": "string",
          "description": "Unique identifier for the tenant."
        },
        "lease_id": {
          "type": "string",
          "description": "Unique identifier for the lease."
        },
        "new_status": {
          "type": "string",
          "enum": [
            "not_started",
            "notice_sent",
            "negotiating",
            "accepted",
            "vacating",
            "expired"
          ],
          "description": "The new status to apply to the renewal process."
        }
      },
      "required": [
        "tenant_id",
        "lease_id",
        "new_status"
      ]
    },
    "example_output": {
      "success": true,
      "current_status": "accepted"
    }
  }
}
